from pathlib import Path
import re
valid = {'read_file','write_file','replace','run_shell_command','grep_search','list_directory','google_web_search','web_fetch','glob','read_many_files'}
for path in sorted(Path('agents').glob('*.md')):
    text = path.read_text()
    if not text.startswith('---\n'):
        raise SystemExit(f'missing frontmatter: {path}')
    _, fm, _ = text.split('---', 2)
    if 'kind: local' not in fm:
        raise SystemExit(f'wrong kind: {path}')
    tools = []
    in_tools = False
    for line in fm.splitlines():
        if line.startswith('tools:'):
            in_tools = True
            continue
        if in_tools:
            if re.match(r'^[A-Za-z_]', line):
                in_tools = False
            elif line.strip().startswith('- '):
                tools.append(line.strip()[2:])
    bad = [t for t in tools if t not in valid]
    if bad:
        raise SystemExit(f'invalid tools in {path}: {bad}')
print('agent frontmatter validated')
